export enum TicketStatus {
  WAITING = 'WAITING',
  CALLING = 'CALLING',
  ATTENDING = 'ATTENDING',
  COMPLETED = 'COMPLETED',
  CANCELLED = 'CANCELLED'
}

export enum UserRole {
  SUPERADMIN = 'SUPERADMIN',
  ADMIN = 'ADMIN',
  STAFF = 'STAFF',
  TOTEM = 'TOTEM'
}

export interface User {
  id: string;
  username: string;
  password?: string;
  role: UserRole;
  name: string;
  assignedStationId?: string;
}

export interface Service {
  id: string;
  name: string;
  prefix: string;
  color: string;
  description: string;
