  calledAt?: number;
  startedAt?: number;
  endedAt?: number;
  stationId?: string;
  metadata?: {
    priority?: boolean;
    recalledCount?: number;
  };
}

export interface QmsState {
  services: Service[];
  stations: Station[];
  tickets: Ticket[];
  nextSequence: Record<string, number>;
  users: User[];
  currentUser: User | null;
}

import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

const DEFAULT_USERS: User[] = [
  { id: 'u1', username: 'superadmin', password: '123', name: 'Super Administrador', role: UserRole.SUPERADMIN },
  { id: 'u2', username: 'admin', password: '123', name: 'Gestor Operativo', role: UserRole.ADMIN },
  { id: 'u3', username: 'staff1', password: '123', name: 'Operario 01', role: UserRole.STAFF, assignedStationId: 's1' },
  { id: 'u4', username: 'totem', password: '123', name: 'Tótem Entrada', role: UserRole.TOTEM },
];

const STORAGE_KEY = 'gesfil_v2_state';

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        return {
          ...parsed,
          services: (parsed.services || INITIAL_SERVICES).map((s: any) => ({ ...s, active: s.active ?? true })),
          stations: (parsed.stations || INITIAL_STATIONS).map((s: any) => ({ ...s, active: s.active ?? true })),
          users: parsed.users || DEFAULT_USERS,
          tickets: parsed.tickets || [],
          currentUser: parsed.currentUser || null,
          nextSequence: parsed.nextSequence || {}
        };
      }
    } catch (e) {
      console.error("Error de hidratación:", e);
    }
    return {
      services: INITIAL_SERVICES,
      stations: INITIAL_STATIONS,
      tickets: [],
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      users: DEFAULT_USERS,
      currentUser: null,
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const login = useCallback((username: string, password?: string) => {
    const user = state.users.find(u => u.username.toLowerCase() === username.trim().toLowerCase() && u.password === password);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      return true;
    }
    return false;
  }, [state.users]);

  const logout = useCallback(() => setState(prev => ({ ...prev, currentUser: null })), []);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service || !service.active) return prev;
      const sequence = prev.nextSequence[serviceId] || 101;
      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code: `${service.prefix}-${sequence}`,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
      };
      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: { ...prev.nextSequence, [serviceId]: sequence + 1 }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, newStatus: TicketStatus, stationId?: string) => {
    setState(prev => {
      const idx = prev.tickets.findIndex(t => t.id === ticketId);
      if (idx === -1) return prev;
      const t = prev.tickets[idx];

      // Validación de Máquina de Estados
      const isLegal = 
        (t.status === TicketStatus.WAITING && newStatus === TicketStatus.CALLING) ||
        (t.status === TicketStatus.CALLING && (newStatus === TicketStatus.ATTENDING || newStatus === TicketStatus.CANCELLED || newStatus === TicketStatus.CALLING)) ||
        (t.status === TicketStatus.ATTENDING && (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED));

      if (!isLegal && newStatus !== t.status) return prev;

      const updated = [...prev.tickets];
      const updates: Partial<Ticket> = { status: newStatus };

      if (newStatus === TicketStatus.CALLING) {
        updates.calledAt = Date.now();
        updates.stationId = stationId || t.stationId;
        updates.metadata = { ...t.metadata, recalledCount: (t.metadata?.recalledCount || 0) + 1 };
      } else if (newStatus === TicketStatus.ATTENDING) {
        updates.startedAt = t.startedAt || Date.now();
      } else if (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED) {
        updates.endedAt = Date.now();
      }

      updated[idx] = { ...t, ...updates };
      return { ...prev, tickets: updated };
    });
  }, []);

  // Funciones de Gestión Administrativa
  const addUser = (u: Omit<User, 'id'>) => setState(p => ({ ...p, users: [...p.users, { ...u, id: crypto.randomUUID() }] }));
  const updateUser = (id: string, u: Partial<User>) => setState(p => ({ ...p, users: p.users.map(x => x.id === id ? { ...x, ...u } : x) }));
  const deleteUser = (id: string) => setState(p => ({ ...p, users: p.users.filter(x => x.id !== id) }));

  const addService = (s: Omit<Service, 'id'>) => {
    const id = crypto.randomUUID();
    setState(p => ({ ...p, services: [...p.services, { ...s, id }], nextSequence: { ...p.nextSequence, [id]: 101 } }));
  };
  const updateService = (id: string, s: Partial<Service>) => setState(p => ({ ...p, services: p.services.map(x => x.id === id ? { ...x, ...s } : x) }));
  const deleteService = (id: string) => setState(p => ({
    ...p,
    services: p.services.filter(x => x.id !== id),
    stations: p.stations.map(st => ({ ...st, serviceIds: st.serviceIds.filter(sid => sid !== id) }))
  }));

  const addStation = (s: Omit<Station, 'id'>) => setState(p => ({ ...p, stations: [...p.stations, { ...s, id: crypto.randomUUID() }] }));
  const updateStation = (id: string, s: Partial<Station>) => setState(p => ({ ...p, stations: p.stations.map(x => x.id === id ? { ...x, ...s } : x) }));
  const deleteStation = (id: string) => setState(p => ({ ...p, stations: p.stations.filter(x => x.id !== id) }));

  const resetSystem = () => {
    if (confirm("¿Reiniciar transacciones?")) {
      setState(p => ({ ...p, tickets: [], nextSequence: p.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}) }));
    }
  };

  return { state, login, logout, addTicket, updateTicketStatus, resetSystem, addUser, updateUser, deleteUser, addService, updateService, deleteService, addStation, updateStation, deleteStation };
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSmartQueueAnalysis = async (tickets: any[], services: any[]) => {
  try {
    const stats = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      return {
        service: s.name,
        total: sTickets.length,
        completed: sTickets.filter(t => t.status === 'COMPLETED').length,
        cancelled: sTickets.filter(t => t.status === 'CANCELLED').length,
      };
    });

    const prompt = `Analiza estos datos de atención hospitalaria y genera una recomendación estratégica breve (max 300 caracteres): ${JSON.stringify(stats)}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Análisis no disponible en este momento.";
  }
};

import React, { useMemo, useState, useEffect } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import TicketTraceabilityModal from './TicketTraceabilityModal';
import { getSmartQueueAnalysis } from '../services/gemini';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
  onToggleService?: (id: string, active: boolean) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations, onToggleService }) => {
  const [inspectingTicket, setInspectingTicket] = useState<Ticket | null>(null);
  const [smartAdvice, setSmartAdvice] = useState<string>('Analizando métricas...');

  useEffect(() => {
    if (tickets.length > 5) {
      getSmartQueueAnalysis(tickets, services).then(setSmartAdvice);
    }
  }, [tickets.length]);

  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;

    const dataByService = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      return {
        name: s.name,
        id: s.id,
        active: s.active,
        value: sTickets.length,
        color: s.color || '#4f46e5'
      };
    });

    return { total, completed, waiting, cancelled, dataByService, recent: [...tickets].reverse().slice(0, 8) };
  }, [tickets, services]);

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 border-b border-slate-200 pb-10">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">BI Dashboard <span className="text-indigo-600">Enterprise</span></h1>
          <p className="text-slate-500 font-medium">Monitorización de flujo en tiempo real</p>
        </div>

        <div className="bg-indigo-900 text-white p-6 rounded-[2rem] max-w-md shadow-xl border border-indigo-700 relative overflow-hidden group">
           <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-125 transition-transform">✨</div>
           <p className="text-[9px] font-black uppercase tracking-[0.2em] text-indigo-300 mb-2">IA Insights (Gemini)</p>
           <p className="text-xs font-bold leading-relaxed">{smartAdvice}</p>
        </div>
      </header>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Total Tickets', val: stats.total, color: 'text-slate-900' },
          { label: 'En Cola', val: stats.waiting, color: 'text-amber-500' },
          { label: 'Atendidos', val: stats.completed, color: 'text-emerald-500' },
          { label: 'Cancelados', val: stats.cancelled, color: 'text-rose-500' },
        ].map((k, i) => (
          <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-200/60 shadow-sm">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">{k.label}</p>
            <p className={`text-4xl font-black ${k.color}`}>{k.val}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 bg-white p-10 rounded-[3rem] border border-slate-200 shadow-sm">
           <h3 className="text-xl font-black text-slate-900 mb-8">Demanda por Departamento</h3>
           <div className="h-[300px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={stats.dataByService}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
                  <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                  <Bar dataKey="value" radius={[10, 10, 10, 10]} barSize={40}>
                    {stats.dataByService.map((e, idx) => <Cell key={idx} fill={e.color} />)}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
           </div>
        </div>

        <div className="lg:col-span-4 bg-slate-900 text-white p-8 rounded-[3rem] shadow-xl">
           <h3 className="text-lg font-black mb-6 uppercase tracking-widest text-indigo-400 text-sm">Actividad Reciente</h3>
           <div className="space-y-4">
              {stats.recent.map(t => (
                <div key={t.id} className="flex items-center justify-between p-3 bg-white/5 rounded-2xl border border-white/5">
                   <div>
                      <p className="text-xs font-black">{t.code}</p>
                      <p className="text-[9px] text-slate-500">{new Date(t.createdAt).toLocaleTimeString()}</p>
                   </div>
                   <button onClick={() => setInspectingTicket(t)} className="text-[10px] font-bold text-indigo-400 hover:underline">Ver</button>
                </div>
              ))}
           </div>
        </div>
      </div>

      {inspectingTicket && (
        <TicketTraceabilityModal 
          ticket={inspectingTicket}
          service={services.find(s => s.id === inspectingTicket.serviceId)}
          station={stations.find(st => st.id === inspectingTicket.stationId)}
          onClose={() => setInspectingTicket(null)}
        />
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useMemo, useEffect } from 'react';
import { Ticket, Station, Service, TicketStatus, UserRole } from '../types';

interface StaffViewProps {
  station: Station;
  allStations?: Station[];
  tickets: Ticket[];
  services: Service[];
  userRole?: UserRole;
  onStatusUpdate: (ticketId: string, status: TicketStatus, stationId: string) => void;
  onSelectStation?: (stationId: string) => void;
}

const StaffView: React.FC<StaffViewProps> = ({ station, allStations = [], tickets, services, userRole, onStatusUpdate, onSelectStation }) => {
  const [elapsed, setElapsed] = useState(0);
  const isAdmin = userRole === UserRole.ADMIN || userRole === UserRole.SUPERADMIN;

  const activeTicket = useMemo(() => 
    tickets.find(t => t.stationId === station.id && (t.status === TicketStatus.CALLING || t.status === TicketStatus.ATTENDING)),
  [tickets, station.id]);

  useEffect(() => {
    let timer: any;
    if (activeTicket?.status === TicketStatus.ATTENDING && activeTicket.startedAt) {
      timer = setInterval(() => setElapsed(Math.floor((Date.now() - activeTicket.startedAt!) / 1000)), 1000);
    } else {
      setElapsed(0);
    }
    return () => clearInterval(timer);
  }, [activeTicket]);

  const waitingTickets = useMemo(() => 
    tickets.filter(t => t.status === TicketStatus.WAITING && station.serviceIds.includes(t.serviceId)),
  [tickets, station.serviceIds]);

  const formatTime = (s: number) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 max-w-[1600px] mx-auto p-4 animate-fade-in">
      <aside className="lg:col-span-3 space-y-6">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100">
           <div className="flex items-center gap-3 mb-4">
              <div className="w-3 h-3 bg-emerald-500 rounded-full animate-pulse"></div>
              <h2 className="text-xl font-black">{station.name}</h2>
           </div>
           <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">{station.operatorName}</p>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
           <div className="p-6 bg-slate-50 border-b border-slate-100 flex justify-between">
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">En Espera</span>
              <span className="bg-slate-900 text-white text-[10px] px-2 py-1 rounded-lg">{waitingTickets.length}</span>
           </div>
           <div className="divide-y divide-slate-50 max-h-[500px] overflow-y-auto">
              {waitingTickets.map(t => (
                <div key={t.id} className="p-6 flex justify-between items-center group hover:bg-indigo-50/30 transition-all">
                   <div>
                      <p className="text-2xl font-black text-slate-900">{t.code}</p>
                      <p className="text-[9px] text-slate-400 font-bold uppercase">{services.find(s=>s.id===t.serviceId)?.name}</p>
                   </div>
                   <button 
                    disabled={!!activeTicket}
                    onClick={() => onStatusUpdate(t.id, TicketStatus.CALLING, station.id)}
                    className="p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 disabled:opacity-20 transition-all"
                   >
                      Llamar
                   </button>
                </div>
              ))}
              {waitingTickets.length === 0 && <div className="p-10 text-center text-slate-300 italic text-sm">Sin pendientes</div>}
           </div>
        </div>
      </aside>

      <main className="lg:col-span-9">
         <div className="bg-white rounded-[4rem] h-full shadow-2xl border border-slate-100 flex flex-col items-center justify-center p-12 text-center relative overflow-hidden min-h-[600px]">
            {activeTicket ? (
              <div className="space-y-12 w-full animate-fade-in">
                 <div className="space-y-4">
                    <span className="px-6 py-2 bg-slate-900 text-indigo-400 rounded-full text-[10px] font-black uppercase tracking-[0.3em] shadow-xl">Atención en Curso</span>
                    <h1 className="text-[12vw] font-black text-slate-900 leading-none tracking-tighter">{activeTicket.code}</h1>
                    <p className="text-xl text-slate-400 font-bold">{services.find(s=>s.id===activeTicket.serviceId)?.name}</p>
                 </div>

                 <div className="bg-slate-50 rounded-[3rem] p-10 inline-block border border-slate-100 shadow-inner">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Cronómetro de Productividad</p>
                    <p className="text-8xl font-mono font-black text-slate-900 tabular-nums">{formatTime(elapsed)}</p>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-4 justify-center max-w-2xl mx-auto w-full">
                    {activeTicket.status === TicketStatus.CALLING ? (
                      <>
                        <button onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.ATTENDING, station.id)} className="flex-[2] py-8 bg-indigo-600 text-white rounded-[2rem] font-black text-2xl shadow-2xl hover:scale-[1.02] transition-all">Iniciar Atención</button>
                        <button onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.CANCELLED, station.id)} className="flex-1 py-8 bg-rose-50 text-rose-600 rounded-[2rem] font-black text-sm uppercase tracking-widest">No se presentó</button>
                      </>
                    ) : (
                      <button onClick={() => onStatusUpdate(activeTicket.id, TicketStatus.COMPLETED, station.id)} className="w-full py-8 bg-emerald-600 text-white rounded-[2rem] font-black text-2xl shadow-2xl hover:scale-[1.02] transition-all">Finalizar Trámite</button>
                    )}
                 </div>
              </div>
            ) : (
              <div className="space-y-6 opacity-40">
                 <div className="w-32 h-32 bg-slate-100 rounded-[3rem] border-2 border-dashed border-slate-300 flex items-center justify-center mx-auto text-4xl">💤</div>
