import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

const DEFAULT_USERS: User[] = [
  { id: 'u1', username: 'superadmin', password: '123', name: 'Super Administrador', role: UserRole.SUPERADMIN },
  { id: 'u2', username: 'admin', password: '123', name: 'Gestor Operativo', role: UserRole.ADMIN },
  { id: 'u3', username: 'staff1', password: '123', name: 'Operario 01', role: UserRole.STAFF, assignedStationId: 's1' },
  { id: 'u4', username: 'totem', password: '123', name: 'Tótem Entrada', role: UserRole.TOTEM },
];

const STORAGE_KEY = 'gesfil_qms_v2';

export const useQmsStore = () => {
  const [state, setState] = useState<QmsState>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        return {
          ...parsed,
          services: (parsed.services || INITIAL_SERVICES).map((s: any) => ({ ...s, active: s.active ?? true })),
          stations: (parsed.stations || INITIAL_STATIONS).map((s: any) => ({ ...s, active: s.active ?? true })),
          users: parsed.users || DEFAULT_USERS,
          tickets: parsed.tickets || [],
          currentUser: parsed.currentUser || null,
          nextSequence: parsed.nextSequence || {}
        };
      }
    } catch (e) {
      console.error("Critical Rehydration Error:", e);
    }
    return {
      services: INITIAL_SERVICES,
      stations: INITIAL_STATIONS,
      tickets: [],
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      users: DEFAULT_USERS,
      currentUser: null,
    };
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const login = useCallback((username: string, password?: string) => {
    const user = state.users.find(u => u.username.toLowerCase() === username.trim().toLowerCase() && u.password === password);
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      return true;
    }
    return false;
  }, [state.users]);

  const logout = useCallback(() => setState(prev => ({ ...prev, currentUser: null })), []);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service || !service.active) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code: `${service.prefix}-${sequence}`,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
        metadata: { recalledCount: 0 }
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: { ...prev.nextSequence, [serviceId]: sequence + 1 }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, newStatus: TicketStatus, stationId?: string) => {
    setState(prev => {
      const index = prev.tickets.findIndex(t => t.id === ticketId);
      if (index === -1) return prev;

      const ticket = prev.tickets[index];

      // Validador de Máquina de Estados (State Machine Enforcement)
      const isValidTransition = 
        (ticket.status === TicketStatus.WAITING && newStatus === TicketStatus.CALLING) ||
        (ticket.status === TicketStatus.CALLING && (newStatus === TicketStatus.CALLING || newStatus === TicketStatus.ATTENDING || newStatus === TicketStatus.CANCELLED)) ||
        (ticket.status === TicketStatus.ATTENDING && (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED));

      if (!isValidTransition) return prev;

      // Validación de Módulo
      if (stationId && newStatus === TicketStatus.CALLING) {
        const station = prev.stations.find(s => s.id === stationId);
        if (!station || !station.serviceIds.includes(ticket.serviceId)) return prev;
      }

      const updatedTickets = [...prev.tickets];
      const updates: Partial<Ticket> = { status: newStatus };

      if (newStatus === TicketStatus.CALLING) {
        updates.calledAt = Date.now();
        updates.stationId = stationId || ticket.stationId;
        updates.metadata = { ...ticket.metadata, recalledCount: (ticket.metadata?.recalledCount || 0) + (ticket.status === TicketStatus.CALLING ? 1 : 0) };
      } else if (newStatus === TicketStatus.ATTENDING) {
        updates.startedAt = ticket.startedAt || Date.now();
      } else if (newStatus === TicketStatus.COMPLETED || newStatus === TicketStatus.CANCELLED) {
        updates.endedAt = Date.now();
      }

      updatedTickets[index] = { ...ticket, ...updates };
      return { ...prev, tickets: updatedTickets };
    });
  }, []);

  // CRUD Administrativo con Integridad Referencial (Cascade Cleanup)
  const addUser = (u: Omit<User, 'id'>) => setState(p => ({ ...p, users: [...p.users, { ...u, id: crypto.randomUUID() }] }));
  const updateUser = (id: string, u: Partial<User>) => setState(p => ({ ...p, users: p.users.map(x => x.id === id ? { ...x, ...u } : x) }));
  const deleteUser = (id: string) => setState(p => ({ ...p, users: p.users.filter(x => x.id !== id) }));

  const addService = (s: Omit<Service, 'id'>) => {
    const id = crypto.randomUUID();
    setState(p => ({ ...p, services: [...p.services, { ...s, id }], nextSequence: { ...p.nextSequence, [id]: 101 } }));
  };
  const updateService = (id: string, s: Partial<Service>) => setState(p => ({ ...p, services: p.services.map(x => x.id === id ? { ...x, ...s } : x) }));
  const deleteService = (id: string) => setState(p => ({
    ...p,
    services: p.services.filter(x => x.id !== id),
    stations: p.stations.map(st => ({ ...st, serviceIds: st.serviceIds.filter(sid => sid !== id) }))
  }));

  const addStation = (s: Omit<Station, 'id'>) => setState(p => ({ ...p, stations: [...p.stations, { ...s, id: crypto.randomUUID() }] }));
  const updateStation = (id: string, s: Partial<Station>) => setState(p => ({ ...p, stations: p.stations.map(x => x.id === id ? { ...x, ...s } : x) }));
  const deleteStation = (id: string) => setState(p => ({ 
    ...p, 
    stations: p.stations.filter(x => x.id !== id),
    users: p.users.map(u => u.assignedStationId === id ? { ...u, assignedStationId: undefined } : u)
  }));

  const resetSystem = () => {
    if (confirm("¿Purgar historial de tickets? Esta acción no se puede deshacer.")) {
      setState(p => ({ ...p, tickets: [], nextSequence: p.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}) }));
    }
  };

  return { state, login, logout, addTicket, updateTicketStatus, resetSystem, addUser, updateUser, deleteUser, addService, updateService, deleteService, addStation, updateStation, deleteStation };
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeOperationalHealth = async (tickets: any[], services: any[]) => {
  try {
    const dataSummary = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      return {
        service: s.name,
        total: sTickets.length,
        completed: sTickets.filter(t => t.status === 'COMPLETED').length,
        waiting: sTickets.filter(t => t.status === 'WAITING').length,
        cancelled: sTickets.filter(t => t.status === 'CANCELLED').length,
      };
    });

    const prompt = `Actúa como un experto en eficiencia hospitalaria. Analiza estos datos de atención y proporciona una recomendación táctica de 2 frases para el equipo de gestión: ${JSON.stringify(dataSummary)}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text;
  } catch (error) {
    console.error("AI Analysis Error:", error);
    return "Optimización en tiempo real activa. Analizando patrones de flujo...";
  }
};

